class SecureTokenStore:
    """In-memory token store. In production, use a secure vault or encrypted DB."""

    def __init__(self):
        self._tokens = {}
        self._token_expiry = {}

    def create_token(self, user_id):
        token = secrets.token_urlsafe(64)
        token_hash = hashlib.sha256(token.encode()).hexdigest()
        self._tokens[token_hash] = user_id
        self._token_expiry[token_hash] = datetime.utcnow() + timedelta(hours=1)
        return token

    def validate_token(self, token):
        if not token:
            return None
        token_hash = hashlib.sha256(token.encode()).hexdigest()
        if token_hash not in self._tokens:
            return None
        if datetime.utcnow() > self._token_expiry.get(token_hash, datetime.min):
            del self._tokens[token_hash]
            del self._token_expiry[token_hash]
            return None
        return self._tokens[token_hash]

    def revoke_token(self, token):
        if token:
            token_hash = hashlib.sha256(token.encode()).hexdigest()
            self._tokens.pop(token_hash, None)
            self._token_expiry.pop(token_hash, None)


