def validate_account_id(account_id):
    """Validate account ID format - alphanumeric, 8-20 chars."""
    if not account_id or not isinstance(account_id, str):
        raise ValueError("Account ID is required")
    if not re.match(r'^[A-Za-z0-9]{8,20}$', account_id):
        raise ValueError("Invalid account ID format")
    return account_id


def validate_amount(amount):
    """Validate monetary amount."""
    if amount is None:
        raise ValueError("Amount is required")
    try:
        d = Decimal(str(amount))
    except (InvalidOperation, TypeError):
        raise ValueError("Invalid amount format")
    if d <= 0:
        raise ValueError("Amount must be positive")
    if d > Decimal('1000000'):
        raise ValueError("Amount exceeds maximum transfer limit")
    # Ensure no more than 2 decimal places
    if d.as_tuple().exponent < -2:
        raise ValueError("Amount cannot have more than 2 decimal places")
    return d


def validate_currency(currency):
    """Validate currency code against allowlist."""
    allowed_currencies = {'USD', 'EUR', 'GBP', 'JPY', 'CHF', 'CAD', 'AUD'}
    if not currency or currency.upper() not in allowed_currencies:
        raise ValueError(f"Currency must be one of: {', '.join(sorted(allowed_currencies))}")
    return currency.upper()


