class SOAPActionValidator:
    """
    Middleware to prevent SOAP Action Spoofing.

    SOAP Action spoofing occurs when an attacker sends a SOAP request with a
    SOAPAction header that doesn't match the actual operation in the SOAP body.
    This can bypass security controls that rely solely on the SOAPAction header.

    Defense: We validate that the SOAPAction header matches the actual operation
    name found in the SOAP body XML.
    """

    def __init__(self, app):
        self.app = app

    def __call__(self, environ, start_response):
        # Extract SOAPAction header
        soap_action = environ.get('HTTP_SOAPACTION', '').strip('"').strip("'")

        # Validate SOAPAction is in our allowlist
        if soap_action and soap_action not in SOAP_ACTION_TO_OPERATION:
            logger.warning("Rejected request with unknown SOAPAction: [REDACTED]")
            start_response('403 Forbidden', [('Content-Type', 'text/xml')])
            fault = self._create_soap_fault('Client', 'Unknown SOAPAction')
            return [fault.encode('utf-8')]

        # Read the request body to inspect the actual SOAP operation
        try:
            content_length = int(environ.get('CONTENT_LENGTH', 0))
        except (ValueError, TypeError):
            content_length = 0

        if content_length > 0:
            body = environ['wsgi.input'].read(content_length)

            # Enforce maximum request size (1MB)
            if len(body) > 1048576:
                logger.warning("Rejected oversized SOAP request")
                start_response('413 Request Entity Too Large', [('Content-Type', 'text/xml')])
                fault = self._create_soap_fault('Client', 'Request too large')
                return [fault.encode('utf-8')]

            # Extract the actual operation from the SOAP body
            actual_operation = self._extract_operation_from_body(body)

            if soap_action and actual_operation:
                expected_operation = SOAP_ACTION_TO_OPERATION.get(soap_action)
                if expected_operation and expected_operation != actual_operation:
                    logger.warning(
                        "SOAP Action Spoofing detected! "
                        "SOAPAction header operation does not match body operation. "
                        "Rejecting request."
                    )
                    start_response('403 Forbidden', [('Content-Type', 'text/xml')])
                    fault = self._create_soap_fault(
                        'Client',
                        'SOAPAction header does not match request body operation'
                    )
                    return [fault.encode('utf-8')]

            # Reset the input stream so spyne can read it
            from io import BytesIO
            environ['wsgi.input'] = BytesIO(body)
            environ['CONTENT_LENGTH'] = str(len(body))

        return self.app(environ, start_response)

    def _extract_operation_from_body(self, body):
        """
        Safely extract the operation name from the SOAP body.
        Uses a simple regex approach to avoid XML parsing vulnerabilities (XXE).
        """
        try:
            body_str = body.decode('utf-8', errors='replace')
            # Look for the first element inside <soap:Body> or <Body>
            # Match patterns like <tns:getBalance or <getBalance
            pattern = r'<(?:soap:|SOAP-ENV:)?Body[^>]*>\s*<(?:[a-zA-Z0-9_]+:)?(\w+)'
            match = re.search(pattern, body_str)
            if match:
                return match.group(1)
        except Exception:
            logger.warning("Failed to parse SOAP body for operation extraction")
        return None

    def _create_soap_fault(self, fault_code, fault_string):
        return (
            '<?xml version="1.0" encoding="UTF-8"?>'
            '<soap:Envelope xmlns:soap="http://schemas.xmlsoap.org/soap/envelope/">'
            '<soap:Body>'
            '<soap:Fault>'
            f'<faultcode>{fault_code}</faultcode>'
            f'<faultstring>{fault_string}</faultstring>'
            '</soap:Fault>'
            '</soap:Body>'
            '</soap:Envelope>'
        )


