class AuthenticationValidator:
    """Validates authentication tokens in SOAP headers."""

    def __init__(self, app):
        self.app = app

    def __call__(self, environ, start_response):
        # Allow authenticate operation without token
        soap_action = environ.get('HTTP_SOAPACTION', '').strip('"').strip("'")
        if soap_action == 'urn:FinancialServices/authenticate':
            return self.app(environ, start_response)

        # Require Authorization header for all other operations
        auth_header = environ.get('HTTP_AUTHORIZATION', '')
        if not auth_header.startswith('Bearer '):
            logger.info("Request rejected: missing or invalid Authorization header")
            start_response('401 Unauthorized', [
                ('Content-Type', 'text/xml'),
                ('WWW-Authenticate', 'Bearer')
            ])
            fault = (
                '<?xml version="1.0" encoding="UTF-8"?>'
                '<soap:Envelope xmlns:soap="http://schemas.xmlsoap.org/soap/envelope/">'
                '<soap:Body><soap:Fault>'
                '<faultcode>Client</faultcode>'
                '<faultstring>Authentication required</faultstring>'
                '</soap:Fault></soap:Body></soap:Envelope>'
            )
            return [fault.encode('utf-8')]

        token = auth_header[7:]
        user_id = token_store.validate_token(token)
        if not user_id:
            logger.info("Request rejected: invalid or expired token")
            start_response('401 Unauthorized', [('Content-Type', 'text/xml')])
            fault = (
                '<?xml version="1.0" encoding="UTF-8"?>'
                '<soap:Envelope xmlns:soap="http://schemas.xmlsoap.org/soap/envelope/">'
                '<soap:Body><soap:Fault>'
                '<faultcode>Client</faultcode>'
                '<faultstring>Invalid or expired authentication token</faultstring>'
                '</soap:Fault></soap:Body></soap:Envelope>'
            )
            return [fault.encode('utf-8')]

        # Store authenticated user in environ for downstream use
        environ['authenticated_user'] = user_id
        return self.app(environ, start_response)


