    @srpc(Unicode, Unicode, SpyneDecimal, Unicode, Unicode,
          _returns=TransferResponse,
          _out_variable_name='TransferResponse',
          _soap_action='urn:FinancialServices/transferFunds')
    def transferFunds(from_account, to_account, amount, currency, reference):
        """Transfer funds between accounts. Requires authentication."""
        response = TransferResponse()

        # Validate all inputs
        try:
            from_account = validate_account_id(from_account)
            to_account = validate_account_id(to_account)
            validated_amount = validate_amount(amount)
            currency = validate_currency(currency)
        except ValueError as e:
            response.success = False
            response.message = str(e)
            return response

        # Validate reference
        if reference and not re.match(r'^[A-Za-z0-9\-_ ]{1,100}$', reference):
            response.success = False
            response.message = 'Invalid reference format'
            return response

        # Cannot transfer to same account
        if from_account == to_account:
            response.success = False
            response.message = 'Cannot transfer to the same account'
            return response

        # Verify accounts exist and are active
        source = account_store.get_account(from_account)
        dest = account_store.get_account(to_account)

        if not source:
            response.success = False
            response.message = 'Source account not found'
            return response

        if not dest:
            response.success = False
            response.message = 'Destination account not found'
            return response

        if source['status'] != 'active':
            response.success = False
            response.message = 'Source account is not active'
            return response

        if dest['status'] != 'active':
            response.success = False
            response.message = 'Destination account is not active'
            return response

        # Currency check
        if source['currency'] != currency or dest['currency'] != currency:
            response.success = False
            response.message = 'Currency mismatch with account currencies'
            return response

        # Sufficient funds check
        if source['balance'] < validated_amount:
            response.success = False
            response.message = 'Insufficient funds'
            return response

        # Execute transfer (in production, this would be an atomic DB transaction)
        new_source_balance = source['balance'] - validated_amount
        new_dest_balance = dest['balance'] + validated_amount

        account_store.update_balance(from_account, new_source_balance)
        account_store.update_balance(to_account, new_dest_balance)

        # Generate transaction ID
        transaction_id = f"TXN{secrets.token_hex(8).upper()}"

        response.transaction_id = transaction_id
        response.status = 'COMPLETED'
        response.from_account = from_account
        response.to_account = to_account
        response.amount = validated_amount
        response.currency = currency
        response.timestamp = datetime.utcnow()
        response.success = True
        response.message = 'Transfer completed successfully'

        logger.info(f"Transfer completed: transaction_id={transaction_id}")
        return response

