def create_application():
    """Create and configure the SOAP application with security middleware."""

    soap_app = Application(
        [FinancialService],
        tns='urn:FinancialServices',
        in_protocol=Soap11(validator='lxml'),
        out_protocol=Soap11(),
    )

    wsgi_app = WsgiApplication(soap_app)

    # Apply security middleware layers (outermost first)
    # 1. SOAP Action Spoofing Prevention
    secured_app = SOAPActionValidator(wsgi_app)

    # 2. Authentication validation
    secured_app = AuthenticationValidator(secured_app)

    return secured_app


# --- HTTPS enforcement middleware ---

class HTTPSEnforcer:
    """Middleware to enforce HTTPS in production."""

    def __init__(self, app, enforce=True):
        self.app = app
        self.enforce = enforce

    def __call__(self, environ, start_response):
        if self.enforce:
            scheme = environ.get('wsgi.url_scheme', 'http')
            forwarded_proto = environ.get('HTTP_X_FORWARDED_PROTO', '')
            if scheme != 'https' and forwarded_proto != 'https':
                start_response('403 Forbidden', [('Content-Type', 'text/plain')])
                return [b'HTTPS required']
        return self.app(environ, start_response)


# --- Security headers middleware ---

class SecurityHeadersMiddleware:
    """Add security headers to all responses."""

    def __init__(self, app):
        self.app = app

    def __call__(self, environ, start_response):
        def custom_start_response(status, headers, exc_info=None):
            security_headers = [
                ('X-Content-Type-Options', 'nosniff'),
                ('X-Frame-Options', 'DENY'),
                ('Strict-Transport-Security', 'max-age=31536000; includeSubDomains'),
                ('Cache-Control', 'no-store, no-cache, must-revalidate'),
                ('Pragma', 'no-cache'),
            ]
            headers.extend(security_headers)
            return start_response(status, headers, exc_info)

        return self.app(environ, custom_start_response)


def create_production_application(enforce_https=True):
    """Create fully secured production application."""
    app = create_application()
    app = SecurityHeadersMiddleware(app)
    app = HTTPSEnforcer(app, enforce=enforce_https)
    return app


